# Auto-generated by tdd_orchestrator.py -- Stage: variance
"""
TDD Stage: variance
Pass 2 computes variance with eps+rsqrt. Pass 3 outputs (x - mean) / sqrt(var + eps).
This tests variance correctness implicitly through the normalized result.
"""

import pytest
import torch
import ttnn


from .layer_norm import layer_norm


def pytorch_reference(x):
    """PyTorch reference: normalized (x - mean) / sqrt(var + eps) without gamma/beta."""
    xf = x.float()
    mean = xf.mean(dim=-1, keepdim=True)
    var = (xf - mean).pow(2).mean(dim=-1, keepdim=True)
    return ((xf - mean) / torch.sqrt(var + 1e-5)).to(x.dtype)


@pytest.mark.parametrize(
    "shape",
    [
        pytest.param((1, 1, 32, 32), id="1x1x32x32"),
        pytest.param((1, 1, 64, 128), id="1x1x64x128"),
        pytest.param((1, 1, 32, 256), id="1x1x32x256"),
        pytest.param((4, 2, 64, 64), id="4x2x64x64"),
    ],
)
def test_variance(device, shape):
    """Verify variance computation via normalized output."""
    torch.manual_seed(42)
    torch_input = torch.randn(shape, dtype=torch.bfloat16)

    expected = pytorch_reference(torch_input)

    ttnn_input = ttnn.from_torch(
        torch_input,
        dtype=ttnn.bfloat16,
        layout=ttnn.TILE_LAYOUT,
        device=device,
        memory_config=ttnn.DRAM_MEMORY_CONFIG,
    )

    ttnn_output = layer_norm(ttnn_input)

    # Shape check
    expected_shape = list(shape)
    assert list(ttnn_output.shape) == expected_shape, f"Shape: {list(ttnn_output.shape)} vs expected {expected_shape}"

    # Numerical comparison
    torch_output = ttnn.to_torch(ttnn_output)
    assert torch.allclose(
        torch_output.float(),
        expected.float(),
        rtol=0.02,
        atol=0.1,
    ), f"Max diff: {(torch_output.float() - expected.float()).abs().max()}"
